- 'Top five' means the list will show only the top five artists with the most tracks.

sql:
SELECT COUNT(*)
FROM playlists
WHERE followers > 10000;

SELECT playlist_name 
FROM playlists 
WHERE playlist_id = 10;

SELECT playlist_id, playlist_name, description, followers
FROM playlists
ORDER BY followers DESC;

SELECT COUNT(*) AS num_tracks
FROM tracks
WHERE danceability > 0.8 AND mode = 1;

